const ppo = $('2단계: PPO 강화학습 포트폴리오 추천').item.json;
const rag = $('3단계: RAG AI 시장 분석').item.json;
const market = $('1단계: 실시간 시장 데이터 수집').item.json;

const now = new Date();
const fng = market?.crypto?.fearGreed?.value ?? 50;
const fngNum = parseInt(fng) || 50;
const fngLabel = fngNum < 25 ? 'Extreme Fear' : fngNum < 45 ? 'Fear' : fngNum < 55 ? 'Neutral' : fngNum < 75 ? 'Greed' : 'Extreme Greed';
const fngKo = fngNum < 25 ? '극도의 공포' : fngNum < 45 ? '공포' : fngNum < 55 ? '중립' : fngNum < 75 ? '탐욕' : '극도의 탐욕';

const weights = ppo?.weights ?? {};
const topAssets = Object.entries(weights)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([k, v]) => k + ' ' + (v * 100).toFixed(1) + '%')
  .join(', ');

const weightLines = Object.entries(weights)
  .map(([k, v]) => '  - ' + k + ': ' + (v * 100).toFixed(1) + '%')
  .join('\n');

const grade = fngNum >= 60 ? 'A' : fngNum >= 40 ? 'B' : 'C';
const aiAnswer = rag?.answer ?? '분석 결과 없음';

const stocks = market?.stocks ?? {};
const crypto = market?.crypto?.coins ?? {};
const stockLines = Object.entries(stocks).slice(0, 4)
  .map(([k, v]) => '  ' + k.toUpperCase() + ': $' + (v.price ?? '-') + ' (' + (v.change ?? 0).toFixed(2) + '%)')
  .join('\n');
const cryptoLines = Object.entries(crypto).slice(0, 3)
  .map(([k, v]) => '  ' + k.toUpperCase() + ': $' + (v.usd ?? '-'))
  .join('\n');

const content = '[V-Invest AI 리포트 - ' + now.toLocaleString('ko-KR') + ']\n\n■ 시장 심리 지수\n공포탐욕: ' + fngNum + '/100 (' + fngKo + ')\n\n■ 주요 주식 시세 (Finnhub)\n' + stockLines + '\n\n■ 암호화폐 시세 (Binance)\n' + cryptoLines + '\n\n■ PPO 강화학습 추천 포트폴리오\n' + weightLines + '\n  Top 3: ' + topAssets + '\n\n■ RAG AI 분석 (뉴스·거시경제 기반)\n' + aiAnswer;

return [{
  json: {
    content,
    sentimentScore: fngNum,
    sentimentLabel: fngLabel,
    grade,
    score: fngNum,
    top_assets: topAssets,
    ai_answer: aiAnswer,
    ppo_weights: weights
  }
}];
